using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ──────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ReturnsCorrectFormat()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");

        Assert.AreEqual("(123) 456-7890", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.StartsWith(result, "(800)");
    }

    [TestMethod]
    public void FormatPhoneNumber_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ContainsDashSeparator()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatPhoneNumber_MatchesPattern()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.Matches(result, new(@"^\(\d{3}\) \d{3}-\d{4}$"));
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_Throws()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    [DataRow("")]
    public void FormatPhoneNumber_WrongLength_Throws(string digits)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    // ── BuildGreeting ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ReturnsCorrectGreeting()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");

        StringAssert.StartsWith(result, "Dear ");
    }

    [TestMethod]
    public void BuildGreeting_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_ContainsName()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");

        StringAssert.Contains(result, "Jones");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_IncludesTitle()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");

        StringAssert.Contains(result, "Dr.");
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_InvalidName_Throws(string? name)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // ── GenerateSlug ───────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleSentence_ReturnsSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("My First Blog Post!");

        StringAssert.Matches(result, new(@"^[a-z0-9]+(-[a-z0-9]+)*$"));
    }

    [TestMethod]
    public void GenerateSlug_DoesNotStartWithDash()
    {
        var result = _formatter.GenerateSlug("  --Leading Dashes  ");

        StringAssert.DoesNotMatch(result, new(@"^-"));
    }

    [TestMethod]
    public void GenerateSlug_DoesNotEndWithDash()
    {
        var result = _formatter.GenerateSlug("Trailing Symbols!@#");

        StringAssert.DoesNotMatch(result, new(@"-$"));
    }

    [TestMethod]
    public void GenerateSlug_SpecialChars_CollapsedToSingleDash()
    {
        var result = _formatter.GenerateSlug("C# & .NET: A Guide");

        // Multiple special chars between words become a single dash
        StringAssert.DoesNotMatch(result, new(@"--"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_InvalidTitle_Throws(string? title)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // ── FormatCurrency ─────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_ReturnsDollarAmount()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.AreEqual("$9.99", result);
    }

    [TestMethod]
    public void FormatCurrency_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(42.5m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(100m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinus()
    {
        var result = _formatter.FormatCurrency(-5.50m);

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatCurrency_MatchesDecimalFormat()
    {
        var result = _formatter.FormatCurrency(1234.5m, "£");

        StringAssert.Matches(result, new(@"^£\d+\.\d{2}$"));
    }

    [TestMethod]
    public void FormatCurrency_Zero_FormatsCorrectly()
    {
        var result = _formatter.FormatCurrency(0m);

        Assert.AreEqual("$0.00", result);
    }
}

